97: func (s *Service) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
98: 	if req == nil {
99: 		return errNilRequest
100: 	}
101: 
102: 	if sender == nil {
103: 		return errNilSender
104: 	}
