244: func handleQuery(ctx context.Context, raw query.QueryDataRequest, b QueryAPIBuilder, httpreq *http.Request, responder responderWrapper, connectLogger log.Logger) (*backend.QueryDataResponse, error) {
245: 	var jsonQueries = make([]*simplejson.Json, 0, len(raw.Queries))
246: 	for _, query := range raw.Queries {
247: 		dsRef, err := getValidDataSourceRef(ctx, query.Datasource, query.DatasourceID, b.legacyDatasourceLookup)
248: 		if err != nil {
249: 			connectLogger.Error("error getting valid datasource ref", err)
250: 		}
251: 		if dsRef != nil {
252: 			query.Datasource = dsRef
253: 		}
254: 
255: 		jsonBytes, err := json.Marshal(query)
256: 		if err != nil {
257: 			connectLogger.Error("error marshalling", err)
258: 		}
259: 
260: 		sjQuery, _ := simplejson.NewJson(jsonBytes)
261: 		if err != nil {
262: 			connectLogger.Error("error unmarshalling", err)
263: 		}
264: 
265: 		jsonQueries = append(jsonQueries, sjQuery)
266: 	}
267: 
268: 	mReq := dtos.MetricRequest{
269: 		From:    raw.From,
270: 		To:      raw.To,
271: 		Queries: jsonQueries,
272: 	}
273: 
274: 	cache := &MyCacheService{
275: 		legacy: b.legacyDatasourceLookup,
276: 	}
277: 
278: 	headers := ExtractKnownHeaders(httpreq.Header)
279: 
280: 	instance, err := b.instanceProvider.GetInstance(ctx, connectLogger, headers)
281: 	if err != nil {
282: 		connectLogger.Error("failed to get instance configuration settings", "err", err)
283: 		responder.Error(err)
284: 		return nil, err
285: 	}
286: 
287: 	instanceConfig := instance.GetSettings()
288: 
289: 	dsQuerierLoggerWithSlug := instance.GetLogger()
290: 
291: 	qsDsClientBuilder := dsquerierclient.NewQsDatasourceClientBuilderWithInstance(
292: 		instance,
293: 		ctx,
294: 		dsQuerierLoggerWithSlug,
295: 	)
296: 
297: 	exprService := expr.ProvideService(
298: 		&setting.Cfg{
299: 			ExpressionsEnabled:            instanceConfig.ExpressionsEnabled,
300: 			SQLExpressionCellLimit:        instanceConfig.SQLExpressionCellLimit,
301: 			SQLExpressionOutputCellLimit:  instanceConfig.SQLExpressionOutputCellLimit,
302: 			SQLExpressionTimeout:          instanceConfig.SQLExpressionTimeout,
303: 			SQLExpressionQueryLengthLimit: instanceConfig.SQLExpressionQueryLengthLimit,
304: 		},
305: 		nil,
306: 		nil,
307: 		instanceConfig.FeatureToggles,
308: 		nil,
309: 		b.tracer,
310: 		qsDsClientBuilder,
311: 	)
312: 
313: 	qdr, err := service.QueryData(ctx, dsQuerierLoggerWithSlug, cache, exprService, mReq, qsDsClientBuilder, headers)
314: 
315: 	// tell the `instance` structure that it can now report
316: 	// metrics that are only reported once during a request
317: 	instance.ReportMetrics()
318: 
319: 	if err != nil {
320: 		return qdr, err
321: 	}
322: 
323: 	return qdr, nil
324: }
